import React, { useState } from 'react';
import Calendar from './Calendar.jsx';
import RoomSelector from './RoomSelector.jsx';
import GuestForm from './GuestForm.jsx';
import BookingSummary from './BookingSummary.jsx';
import { diffDays } from '../data/bookingData.js';
import styles from '../styles/BookingPage.module.css';

const TODAY = new Date();
const CUR_YEAR = TODAY.getFullYear();
const CUR_MONTH = TODAY.getMonth();

const MONTHS_LABEL = [
  'January','February','March','April','May','June',
  'July','August','September','October','November','December'
];

const BookingPage = ({ onConfirm }) => {
  const [checkIn, setCheckIn] = useState(null);
  const [checkOut, setCheckOut] = useState(null);
  const [hoveredDate, setHoveredDate] = useState(null);
  const [selectedRoom, setSelectedRoom] = useState(null);
  const [guests, setGuests] = useState(1);
  const [guestName, setGuestName] = useState('');
  const [guestContact, setGuestContact] = useState('');
  const [contactMethod, setContactMethod] = useState('email');
  const [specialRequests, setSpecialRequests] = useState('');

  const [viewStartMonth, setViewStartMonth] = useState({ year: CUR_YEAR, month: CUR_MONTH });

  const nextViewMonth = viewStartMonth.month === 11
    ? { year: viewStartMonth.year + 1, month: 0 }
    : { year: viewStartMonth.year, month: viewStartMonth.month + 1 };

  const prevMonth = () => {
    setViewStartMonth((v) =>
      v.month === 0 ? { year: v.year - 1, month: 11 } : { year: v.year, month: v.month - 1 }
    );
  };

  const nextMonth = () => {
    setViewStartMonth((v) =>
      v.month === 11 ? { year: v.year + 1, month: 0 } : { year: v.year, month: v.month + 1 }
    );
  };

  const handleDateClick = (dateStr) => {
    if (!checkIn || (checkIn && checkOut)) {
      setCheckIn(dateStr);
      setCheckOut(null);
    } else {
      if (dateStr <= checkIn) {
        setCheckIn(dateStr);
        setCheckOut(null);
      } else {
        setCheckOut(dateStr);
      }
    }
  };

  const handleSubmit = () => {
    const nights = diffDays(checkIn, checkOut);
    const total = selectedRoom ? selectedRoom.price * nights * 1.12 : 0;
    onConfirm({
      checkIn,
      checkOut,
      nights,
      room: selectedRoom,
      guests,
      guestName,
      guestContact,
      contactMethod,
      specialRequests,
      total: Math.round(total),
      refCode: 'MZY-' + Math.random().toString(36).substr(2, 6).toUpperCase(),
    });
  };

  return (
    <div className={styles.page}>
      <div className={styles.container}>
        <div className={styles.leftCol}>

          {/* Section: Calendar */}
          <section className={styles.section}>
            <div className={styles.sectionLabel}>
              <span className={styles.labelLine} />
              <span className={styles.labelText}>Select Your Stay</span>
              <span className={styles.labelLine} />
            </div>

            <div className={styles.legend}>
              <div className={styles.legendItem}>
                <span className={styles.legendDot} style={{ background: 'var(--white)', border: '2px solid var(--mist)' }} />
                <span>Available</span>
              </div>
              <div className={styles.legendItem}>
                <span className={styles.legendDot} style={{ background: 'var(--mist)' }} />
                <span>Booked</span>
              </div>
              <div className={styles.legendItem}>
                <span className={styles.legendDot} style={{ background: 'var(--crimson)' }} />
                <span>Check-in</span>
              </div>
              <div className={styles.legendItem}>
                <span className={styles.legendDot} style={{ background: 'var(--teal)' }} />
                <span>Check-out</span>
              </div>
              <div className={styles.legendItem}>
                <span className={styles.legendDotHighlight} />
                <span style={{ color: 'var(--crimson)' }}>Weekend / Holiday</span>
              </div>
            </div>

            <div className={styles.calNavRow}>
              <button className={styles.navBtn} onClick={prevMonth} type="button">‹</button>
              <span className={styles.calNavLabel}>
                {MONTHS_LABEL[viewStartMonth.month]} – {MONTHS_LABEL[nextViewMonth.month]} {nextViewMonth.year}
              </span>
              <button className={styles.navBtn} onClick={nextMonth} type="button">›</button>
            </div>

            <div className={styles.calendarRow}>
              <Calendar
                year={viewStartMonth.year}
                month={viewStartMonth.month}
                checkIn={checkIn}
                checkOut={checkOut}
                hoveredDate={hoveredDate}
                onDateClick={handleDateClick}
                onDateHover={setHoveredDate}
              />
              <Calendar
                year={nextViewMonth.year}
                month={nextViewMonth.month}
                checkIn={checkIn}
                checkOut={checkOut}
                hoveredDate={hoveredDate}
                onDateClick={handleDateClick}
                onDateHover={setHoveredDate}
              />
            </div>

            {checkIn && !checkOut && (
              <p className={styles.calHint}>
                ✦ Now select your check-out date
              </p>
            )}
            {checkIn && checkOut && (
              <p className={styles.calSuccess}>
                ✦ {diffDays(checkIn, checkOut)} nights selected — perfect!
                <button
                  className={styles.clearBtn}
                  onClick={() => { setCheckIn(null); setCheckOut(null); }}
                  type="button"
                >
                  Clear dates
                </button>
              </p>
            )}
          </section>

          <RoomSelector selectedRoom={selectedRoom} onSelect={setSelectedRoom} />

          <GuestForm
            guestName={guestName}
            setGuestName={setGuestName}
            guestContact={guestContact}
            setGuestContact={setGuestContact}
            contactMethod={contactMethod}
            setContactMethod={setContactMethod}
            guests={guests}
            setGuests={setGuests}
            maxGuests={selectedRoom?.maxGuests}
            specialRequests={specialRequests}
            setSpecialRequests={setSpecialRequests}
          />
        </div>

        <div className={styles.rightCol}>
          <BookingSummary
            checkIn={checkIn}
            checkOut={checkOut}
            room={selectedRoom}
            guests={guests}
            guestName={guestName}
            guestContact={guestContact}
            contactMethod={contactMethod}
            onSubmit={handleSubmit}
          />
        </div>
      </div>
    </div>
  );
};

export default BookingPage;
